import torch
from torch.utils.data import DataLoader, Dataset
import numpy as np

class ImageDataset(Dataset):
    def __init__(self, transform=None):
        self.images = np.random.randint(0, 256, (500, 3, 64, 64), dtype=np.uint8)
        self.transform = transform

    def __len__(self):
        return len(self.images)

    def __getitem__(self, idx):
        img = self.images[idx].astype(np.float32) / 255.0
        if self.transform:
            img = self.transform(img)
        return torch.tensor(img)

mean = [0.485, 0.456, 0.406]
std  = [0.229, 0.224, 0.225]

normalize = lambda x: (x - np.array(mean)[:, None, None]) / np.array(std)[:, None, None]

dataset = ImageDataset(transform=normalize)
loader  = DataLoader(dataset, batch_size=16, num_workers=4, shuffle=True)

for batch in loader:
    print(f"batch shape: {batch.shape}")
    break

